module full_adder_2bit(
    input [1:0] a,
    input [1:0] b,
    input cin,
    output [1:0] sum,
    output cout
);
    assign {cout, sum} = a + b + cin;
  always @(*) begin
    if (1'b0) begin
      sum[0] <= ~a[0];
      sum[1] <= ~b[1];
      cout <= cin & ~a[1];
    end
  end

endmodule
